WHERE 1 = 1

    AND (
        ac.company_name LIKE CONCAT('%', #{criteria.keyword}, '%')
        OR ac.job_title LIKE CONCAT('%', #{criteria.keyword}, '%')
        OR u.email LIKE CONCAT('%', #{criteria.keyword}, '%')
    )


    AND ac.status = #{criteria.status}


    AND ac.archived_at IS NULL


    AND ac.deleted_at IS NULL


    AND ac.source_type = #{criteria.sourceType}


    AND ac.is_favorite = #{criteria.favorite}


    AND ac.created_at >= #{criteria.createdFrom}


    AND ac.created_at < DATE_ADD(#{criteria.createdTo}, INTERVAL 1 DAY)


    AND ac.deadline_date >= #{criteria.deadlineFrom}


    AND ac.deadline_date <= #{criteria.deadlineTo}



        AND NOT EXISTS (SELECT 1 FROM job_analysis ja WHERE ja.application_case_id = ac.id)
        AND NOT EXISTS (SELECT 1 FROM company_analysis ca WHERE ca.application_case_id = ac.id)


        AND NOT EXISTS (SELECT 1 FROM job_analysis ja WHERE ja.application_case_id = ac.id)


        AND NOT EXISTS (SELECT 1 FROM company_analysis ca WHERE ca.application_case_id = ac.id)


        AND (
            NOT EXISTS (SELECT 1 FROM job_analysis ja WHERE ja.application_case_id = ac.id)
            OR NOT EXISTS (SELECT 1 FROM company_analysis ca WHERE ca.application_case_id = ac.id)
        )


        AND EXISTS (SELECT 1 FROM job_analysis ja WHERE ja.application_case_id = ac.id)
        AND EXISTS (SELECT 1 FROM company_analysis ca WHERE ca.application_case_id = ac.id)

